        SELECT r.store_id
        FROM reservations r
        WHERE r.deleted_at IS NULL
        AND DATE(r.event_start_date) <= #{storeListReq.eventEndDate}
        AND DATE(r.event_end_date) >= #{storeListReq.eventStartDate}
        AND r.status IN (
        'CONFIRMED',
        'PAYMENT_COMPLETED',
        'COMPLETED'
        )
        )



        AND s.min_headcount <= #{storeListReq.minHeadcount}


